import { isEqual } from 'lodash-es';
import { useCallback, useEffect, useRef, useSyncExternalStore } from 'react';

import {
  _useOverlayTooltipStore as useOverlayTooltipStore,
  _useOverlayTooltipReducer as useTooltipReducer,
  type _OverlayTooltipGeometryTypes as GeometryTypes,
  type _OverlayTooltipState as TooltipState,
} from '@dynatrace/strato-components/charts';

import { buildGeoTooltipState } from '../utils/build-geo-tooltip-state.js';

type Position = { x: number; y: number } | null | undefined;

export const useOverlayTooltipSelector = <S>(
  selector: (state: TooltipState) => S,
): S => {
  const store = useOverlayTooltipStore();
  const prevRef = useRef<S | undefined>(undefined);

  const getSnapshot = useCallback(() => {
    const next = selector(store.getState());

    if (prevRef.current !== undefined && isEqual(prevRef.current, next)) {
      return prevRef.current;
    }

    prevRef.current = next;
    return next;
  }, [store, selector]);

  return useSyncExternalStore(store.subscribe, getSnapshot);
};

export const useGeoOverlayTooltipState = <T>() => {
  const metadata = useOverlayTooltipSelector(
    (state) => state.data?.metadata as T[] | undefined,
  );
  const pinned = useOverlayTooltipSelector((state) => state.pinned);
  const inBounds = useOverlayTooltipSelector((state) => state.inBounds);

  return { data: metadata, pinned, inBounds };
};

/**
 * Syncs position, pinned state, and layer-specific data from the geo map
 * into the OverlayTooltip store.
 *
 * Position updates set the store state directly because the reducer's
 * SET_POSITION / SET_PINNED rely on `overlay.getBounds()`, which is
 * always `undefined` in the geo context (the overlay ref is never
 * attached to a DOM element).
 *
 * @internal
 */
export const useGeoTooltipSync = (
  position: Position,
  pinned: boolean,
  geometryType: GeometryTypes,
  geoData?: unknown[] | undefined,
) => {
  const store = useOverlayTooltipStore();
  const dispatch = useTooltipReducer();

  useEffect(() => {
    const onScroll = () => {
      if (store.getState().pinned) {
        dispatch({ type: 'TOOLTIP_MOUSE_LEAVE' })();
      }
    };

    document.body.addEventListener('scroll', onScroll, true);
    return () => {
      document.body.removeEventListener('scroll', onScroll, true);
    };
  }, [store, dispatch]);

  useEffect(() => {
    if (position) {
      const nextState = buildGeoTooltipState({
        absoluteX: position.x,
        absoluteY: position.y,
        relativeX: position.x,
        relativeY: position.y,
        pinned,
        geometry: geometryType,
        metadata: geoData,
      });

      const current = store.getState();
      if (
        current.absoluteX !== nextState.absoluteX ||
        current.absoluteY !== nextState.absoluteY ||
        current.inBounds !== nextState.inBounds ||
        current.pinned !== nextState.pinned ||
        !isEqual(current.data?.metadata, nextState.data.metadata)
      ) {
        store.setState(nextState);
      }
    } else {
      const currentState = store.getState();

      // Only dispatch if the store isn't already in the "hidden" state.
      if (currentState.inBounds || currentState.pinned) {
        dispatch({ type: 'SET_OUT_BOUNDS' })();
      }
    }
  }, [
    position?.x,
    position?.y,
    pinned,
    geometryType,
    geoData,
    store,
    dispatch,
  ]);
};
